mapper.select:
SELECT * FROM places
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT * FROM places
WHERE id IN

    #{id}

SELECT *
FROM (
    SELECT *,
        (6371 * acos(
            cos(radians(#{latitude})) * cos(radians(latitude)) *
            cos(radians(longitude) - radians(#{longitude})) +
            sin(radians(#{latitude})) * sin(radians(latitude))
        )) AS distance
    FROM places
    WHERE 1=1

        AND category = #{category}


        AND place_group IN

            #{group}



        AND review_rating >= #{minRating}

) AS places_with_distance
WHERE distance <= #{radius}
ORDER BY distance
LIMIT #{limit} OFFSET #{offset}

SELECT *
FROM (
    SELECT p.*,
        (6371 * acos(
            cos(radians(#{latitude})) * cos(radians(p.latitude)) *
            cos(radians(p.longitude) - radians(#{longitude})) +
            sin(radians(#{latitude})) * sin(radians(p.latitude))
        )) AS distance
    FROM places p

        INNER JOIN place_foods pf ON pf.place_id = p.id

    WHERE 1=1

        AND pf.food_id IN

            #{fid}



        AND p.destinations @> #{citySlugJson}::jsonb


        AND NOT EXISTS (SELECT 1 FROM place_foods pfx WHERE pfx.place_id = p.id)


        AND p.category = #{category}


        AND p.place_group IN

            #{group}



        AND p.review_rating >= #{minRating}

) AS places_with_distance
WHERE distance <= #{radius}
ORDER BY distance
LIMIT #{limit} OFFSET #{offset}
